        costs[i] = cost;
    }

    // DP state: dp[i][j][state]
    // i: current index (1 to n-2)
    // j: number of peaks selected so far (0 to k_max)
    // state: 0 if i is NOT a peak, 1 if i IS a peak.

    // Max possible value for j is k_max.
    // Size: (n-1) * (k_max + 1) * 2

    // Since n <= 10^5, O(n * k_max) is O(n^2), too slow. k_max is O(n).
    // We must use the fact that we only need to select $K_{max}$ peaks.

    // If the problem statement guarantees $K_{max}$ is achievable, we only need min cost for *that* number.

    // Let's re-examine the structure. The set of potential peaks is $P_{cand} = \{1, 2, \dots, n-2\}$.
    // We are selecting an Independent Set $P \subseteq P_{cand}$ such that $|P| = K_{max}$, and $\sum_{i \in P} \text{Cost}(i)$ is minimized.
    // The constraint is that for $i, j \in P$, $|i-j| \ge 2$. This is exactly the Maximum Weight Independent Set problem, but constrained to size $K_{max}$.

    // Since we need exactly $K_{max}$ peaks, we can use DP on the path graph.

    // DP state: dp[i][j][0] = min cost using prefix up to $i$, selecting $j$ peaks, and $i$ is NOT a peak.
    // dp[i][j][1] = min cost using prefix up to $i$, selecting $j$ peaks, and $i$ IS a peak.

    // Index i runs from 1 to n-2.
    let m = n - 2; // Number of potential peak indices
    // j runs from 0 to k_max.

    // Initialize with a large value (infinity)
    const INF: i64 = 1e18 as i64;

    // dp size: (m+1) x (k_max+1) x 2
    let mut dp = vec![vec![[INF; 2]; k_max + 1]; m + 1];

    // Base case: index 1 (first potential peak)
    // j=0, index 1 not peak: dp[1][0][0] = 0
    dp[1][0][0] = 0;
    // j=1, index 1 is peak: dp[1][1][1] = costs[1]
    if k_max >= 1 {
        dp[1][1][1] = costs[1];
    }

    // Transition for i = 2 to m (i.e., indices 2 to n-2)
    for i in 2..=m {
        let cost_i = costs[i];

        for j in 0..=k_max {
            // Case 0: i is NOT a peak
            // Can come from i-1 being peak or not peak, while maintaining j peaks total.
            dp[i][j][0] = std::cmp::min(dp[i - 1][j][0], dp[i - 1][j][1]);

            // Case 1: i IS a peak
            if j >= 1 {
                // Must come from i-1 NOT being a peak (to maintain independence).
                // We use j-1 peaks up to i-1.
                if dp[i - 1][j - 1][0] != INF {
                    dp[i][j][1] = dp[i - 1][j - 1][0] + cost_i;
                }
            }
        }
    }

    // The result is the minimum cost to achieve exactly k_max peaks over the range [1, n-2].
    let result = std::cmp::min(dp[m][k_max][0], dp[m][k_max][1]);

    // If k_max is 0 (i.e., n < 3, handled at start, or n=3 and k_max=1 but DP setup might miss edge cases),
    // we should ensure the answer is 0 if no peaks are possible or required.
    if k_max == 0 {
        return 0;
    }

    result
}
